#!/bin/bash
# Deploy: 8-dashboard.js → VPS
TARGET="/root/projetos/prismatic-labs-hq/vendedor-ai/agents/8-dashboard.js"
TMPB64="/tmp/_b64_dashboard_js.txt"
rm -f "$TMPB64"
printf '%s' '' >> "$TMPB64"
base64 -d "$TMPB64" | gunzip > "$TARGET"
rm -f "$TMPB64"
echo "✓ 8-dashboard.js deployed to $TARGET"
